const email = $input.first().json;

// Extract key fields
const from = email.from?.value?.[0]?.address || 'unknown';
const subject = email.subject || 'No Subject';
const body = email.text || email.snippet || '';
const date = email.date;
const labels = (email.labelIds || []).join(', ');

// Classify namespace
let namespace = 'personal';
const subjectLower = subject.toLowerCase();
if (subjectLower.includes('axiom') || subjectLower.includes('lumena')) namespace = 'axiom';
else if (subjectLower.includes('realty') || subjectLower.includes('property') || subjectLower.includes('mlo')) namespace = 'jrih';
else if (subjectLower.includes('capital') || subjectLower.includes('funding') || subjectLower.includes('dac')) namespace = 'jrih';
else if (subjectLower.includes('kintsugi') || subjectLower.includes('development')) namespace = 'jrih';
else if (subjectLower.includes('heart') || subjectLower.includes('hoj') || subjectLower.includes('foundation')) namespace = 'heart_of_juniper';
else if (subjectLower.includes('invoice') || subjectLower.includes('contract')) namespace = 'jrih';

// Build content for brain
const content = `Email from ${from}: ${subject}\n\n${body.substring(0, 2000)}`;

return [{
  json: {
    content,
    namespace,
    subject,
    from,
    date,
    labels,
    entry_type: 'observation',
    tags: ['email', namespace, from.split('@')[1]?.split('.')[0] || 'unknown']
  }
}];

const result = $input.first().json;
console.log(`[n8n-gmail-ingest] Inserted thought: ${result.id}`);
return [$input.first()];
